Чтобы выполнить патчинг `user_ini_bytes` и `bodyblock_bytes` параллельно, можно использовать стандартную библиотеку потоков C++ (т.е., `<thread>`). В данной модификации вашей программы вместо непосредственного вызова патчинга в главном потоке будут запущены два отдельных потока, каждый из которых будет обрабатывать свою задачу. Обратите внимание, что передача дескриптора устройства (`HANDLE`) в потоки является безопасной операцией, так как он корректно ссылается на драйвер во всех потоках.

Изменения в коде касаются только функции `main`:

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
#include <memory>
#include <Windows.h>
#include <TlHelp32.h>
#include <thread> // Добавляем поддержку потоков
#include "driver_code.h" // В этом файле у вас должны быть определения namespace driver и class ProcessHelper

// Данные функции просто обертывают логику поиска и применения патчей в функции, пригодные для использования в потоках
void patchUserIniSequence(HANDLE driverHandle, DWORD pid) {
    std::vector<BYTE> user_ini_bytes = { /* bytes */ };
    std::vector<BYTE> user_ini_patch = { /* patch bytes */ };
    std::uintptr_t found_user_ini_address = driver::find_memory_sequence(driverHandle, pid, user_ini_bytes, 0x00999999, 0x7FFFFFFF);
    if (found_user_ini_address != 0) {
        std::cout << "[+] User.ini sequence found at: 0x" << std::hex << found_user_ini_address << std::endl;
        driver::replace_memory_sequence(driverHandle, found_user_ini_address, user_ini_patch);
        std::cout << "[+] Sequence has been successfully replaced!\n" << std::endl;
    }
    else {
        std::cout << "[-] User.ini sequence not found.\n" << std::endl;
    }
}

void patchBodyBlockSequence(HANDLE driverHandle, DWORD pid) {
    std::vector<BYTE> bodyblock_bytes = { /* bytes */ };
    std::vector<BYTE> bodyblock_patch = { /* patch bytes */ };
    std::uintptr_t found_bodyblock_address = driver::find_memory_sequence(driverHandle, pid, bodyblock_bytes, 0x00999999, 0x7FFFFFFF);
    if (found_bodyblock_address != 0) {
        std::cout << "[+] Bodyblock sequence found at: 0x" << std::hex << found_bodyblock_address << std::endl;
        driver::replace_memory_sequence(driverHandle, found_bodyblock_address, bodyblock_patch);
