    }
    else {
        std::cout << "[-] Bodyblock sequence not found.\n" << std::endl;
    }
}

int main() {
    // Ваш код до этой точки остается таким же.

    // Использование потоков для параллельного патчинга
    std::thread patchUserIniThread(patchUserIniSequence, driver.get(), pid);
    std::thread patchBodyBlockThread(patchBodyBlockSequence, driver.get(), pid);

    // Ожидание завершения обоих потоков
    patchUserIniThread.join();
    patchBodyBlockThread.join();

    std::cin.get();
    return 0;
}
