    void applyPatch(const std::string& patchName, const std::vector<BYTE>& sequence, const std::vector<BYTE>& patch, std::uintptr_t startAddress, std::uintptr_t endAddress) const {
        std::cout << "[+] Attempting to apply patch: " << patchName << "\n";
        auto foundAddress = driver::find_memory_sequence(driverHandle, pid, sequence, startAddress, endAddress);
        if (foundAddress != 0) {
            std::cout << "[+] " << patchName << " sequence found at: 0x" << std::hex << foundAddress << "\n";
            driver::replace_memory_sequence(driverHandle, foundAddress, patch);
            std::cout << "[+] " << patchName << " has been successfully replaced!\n" << std::endl;
        } else {
            std::cout << "[-] " << patchName << " sequence not found.\n" << std::endl;
        }
    }
};

