    auto bodyBlockPatchTask = std::async(std::launch::async, &MemoryPatcher::applyPatch, &patcher, "BodyBlock Patch", /* bodyblock_bytes */, /* bodyblock_patch */, 0x00999999, 0x7FFFFFFF);

